const text = $json.text || "";
const lower = text.toLowerCase();

let memory = $json.messages || { facts: [] };

// garantir estrutura
if (typeof memory === "string") {
  try {
    memory = JSON.parse(memory);
  } catch {
    memory = { facts: [] };
  }
}

if (!memory.facts) {
  memory.facts = [];
}

// =========================
// 🔥 1. GUARDAR PLANOS (NOVO)
// =========================
if (lower.includes("vou") && lower.includes("amanhã")) {
  const location = text.split("vou")[1]?.trim();

  const newFact = {
    type: "plan",
    location: location,
    date: "amanhã"
  };

  memory.facts.push(newFact);

  return {
    json: {
      messages: memory,
      text: "Guardei o teu plano."
    }
  };
}

// =========================
// 🔥 2. PERGUNTAR PLANOS (NOVO)
// =========================
if (lower.includes("onde vou amanhã")) {
  const plan = memory.facts.find(f => f.type === "plan");

  return {
    json: {
      text: plan
        ? `Vais ${plan.location} amanhã.`
        : "Não tenho planos guardados."
    }
  };
}

// =========================
// 🔥 3. MEMÓRIA GENÉRICA (ANTIGA)
// =========================
const shouldStore =
  lower.includes("meu") ||
  lower.includes("minha") ||
  lower.includes("vou") ||
  lower.includes("tenho") ||
  lower.includes("gosto") ||
  lower.includes("sou") ||
  lower.includes("prefiro") ||
  lower.includes("trabalho") ||
  lower.includes("moro");

const isGeneralFact =
  lower.includes("fica") ||
  lower.includes("é um") ||
  lower.includes("é uma") ||
  lower.includes("são") ||
  lower.includes("existe");

// guardar texto simples (se não for plano)
if (shouldStore && !isGeneralFact) {
  if (!memory.facts.includes(text)) {
    memory.facts.push(text);
  }

  return {
    json: {
      messages: memory,
      text: "Guardei essa informação."
    }
  };
}

// =========================
// 🔥 4. QUERY GENÉRICA
// =========================
const queryKeywords = lower.split(" ");

let found = memory.facts.find(fact => {
  if (typeof fact !== "string") return false;

  const f = fact.toLowerCase();
  return queryKeywords.some(word => word.length > 3 && f.includes(word));
});

if (found) {
  return {
    json: {
      text: found
    }
  };
}

// =========================
// 🔥 FALLBACK
// =========================
return {
  json: {
    text: "Não encontrei informação relevante."
  }
};
